const msg = $('Telegram Trigger').first().json.message;
const chatId = msg.chat.id;
const text = (msg.text || '').trim().toLowerCase();
const raw = (msg.text || '').trim();

if (String(chatId) !== '8631035943') {
  return [{json:{chatId, reply:'Unauthorized'}}];
}

const rows = $('Command Handler').all().map(i => i.json);

let reply = '';

if (text === '/status' || text === 'status') {
  const d = rows[0] || {};
  reply = '\ud83d\udce1 *GDA Status*\n\n\ud83d\udcca Opportunities: ' + (d.opps||'0') + '\n\ud83c\udfaf Capture Plans: ' + (d.captures||'0') + '\n\ud83d\udea8 Errors (24h): ' + (d.errors_24h||'0');

} else if (text === '/pipeline' || text === 'pipeline') {
  if (!rows.length || !rows[0].stage) {
    reply = 'No pipeline data.';
  } else {
    reply = '\ud83d\udcca *Pipeline*\n\n' + rows.map(r => r.stage + ': ' + r.cnt + ' opps ($' + r.value_m + 'M)').join('\n');
  }

} else if (text === '/errors' || text === 'errors') {
  if (!rows.length || !rows[0].workflow_name) {
    reply = '\u2705 No recent errors.';
  } else {
    reply = '\ud83d\udea8 *Recent Errors*\n\n' + rows.map(r => '\u2022 *' + (r.workflow_name||'?') + '*\n  ' + (r.error_message||'--').substring(0,120)).join('\n\n');
  }

} else if (text === '/briefing' || text === 'briefing') {
  const b = rows[0];
  if (!b || !b.briefing) {
    reply = 'No briefing yet. Next run 6:00 AM ET.';
  } else {
    reply = '\ud83d\udcf0 *Morning Briefing*\n\n' + b.briefing.substring(0, 3800);
  }

} else if (text === '/help' || text === '/start' || text === 'help') {
  reply = '\ud83d\udce1 *GDA Command Bot*\n\nCommands:\n/status \u2014 Platform health\n/errors \u2014 Recent errors\n/pipeline \u2014 Pipeline summary\n/briefing \u2014 Latest intel briefing';

} else {
  reply = '\u2753 Try: /status  /errors  /pipeline  /briefing  /help';
}

return [{json:{chatId, reply: reply.substring(0, 4000)}}];
